def solve(creatinine_clearance, hematocrit, heart_rate, systolic_blood_pressure, gender, heart_failure_signs, diabetes, vascular_disease_or_stroke_history):
    # Step 1: Calculate the score based on creatinine clearance
    if creatinine_clearance <= 15:
        muscle_creatinine_score = 39
    elif 16 <= creatinine_clearance <= 30:
        muscle_creatinine_score = 35
    elif 31 <= creatinine_clearance <= 60:
        muscle_creatinine_score = 28
    elif 61 <= creatinine_clearance <= 90:
        muscle_creatinine_score = 17
    elif 91 <= creatinine_clearance <= 120:
        muscle_creatinine_score = 7
    else:
        muscle_creatinine_score = 0
    yield {
        "step_name": "muscle_creatinine_clearance_score",
        "step_description": "Calculate the score based on the patient's creatinine clearance value.",
        "step_result": muscle_creatinine_score,
        "unit": None
    }

    # Step 2: Calculate the score based on hematocrit
    if hematocrit < 31.0:
        hematocrit_score = 9
    elif 31.0 <= hematocrit <= 33.9:
        hematocrit_score = 7
    elif 34.0 <= hematocrit <= 36.9:
        hematocrit_score = 3
    elif 37.0 <= hematocrit <= 39.9:
        hematocrit_score = 2
    else:
        hematocrit_score = 0
    yield {
        "step_name": "hematocrit_score",
        "step_description": "Calculate the score based on the patient's baseline hematocrit value.",
        "step_result": hematocrit_score,
        "unit": None
    }

    # Step 3: Calculate the score based on heart rate
    if heart_rate <= 70:
        heart_rate_score = 0
    elif 71 <= heart_rate <= 80:
        heart_rate_score = 1
    elif 81 <= heart_rate <= 90:
        heart_rate_score = 3
    elif 91 <= heart_rate <= 100:
        heart_rate_score = 6
    elif 101 <= heart_rate <= 110:
        heart_rate_score = 8
    elif 111 <= heart_rate <= 120:
        heart_rate_score = 10
    else:
        heart_rate_score = 11
    yield {
        "step_name": "heart_rate_score",
        "step_description": "Calculate the score based on the patient's heart rate.",
        "step_result": heart_rate_score,
        "unit": None
    }

    # Step 4: Calculate the score based on systolic blood pressure
    if systolic_blood_pressure <= 90:
        systolic_blood_pressure_score = 10
    elif 91 <= systolic_blood_pressure <= 100:
        systolic_blood_pressure_score = 8
    elif 101 <= systolic_blood_pressure <= 120:
        systolic_blood_pressure_score = 5
    elif 121 <= systolic_blood_pressure <= 180:
        systolic_blood_pressure_score = 1
    elif 181 <= systolic_blood_pressure <= 200:
        systolic_blood_pressure_score = 3
    else:
        systolic_blood_pressure_score = 5
    yield {
        "step_name": "systolic_blood_pressure_score",
        "step_description": "Calculate the score based on the patient's systolic blood pressure.",
        "step_result": systolic_blood_pressure_score,
        "unit": None
    }

    # Step 5: Calculate the score based on gender
    if gender == "Male":
        gender_score = 0
    else:
        gender_score = 8
    yield {
        "step_name": "gender_score",
        "step_description": "Calculate the score based on the patient's gender.",
        "step_result": gender_score,
        "unit": None
    }

    # Step 6: Calculate the score based on presence of signs of heart failure
    if heart_failure_signs == "No":
        heart_failure_signs_score = 0
    else:
        heart_failure_signs_score = 7
    yield {
        "step_name": "heart_failure_signs_score",
        "step_description": "Calculate the score based on the presence of signs of heart failure.",
        "step_result": heart_failure_signs_score,
        "unit": None
    }

    # Step 7: Calculate the score based on presence of diabetes
    if diabetes == "No":
        diabetes_score = 0
    else:
        diabetes_score = 6
    yield {
        "step_name": "diabetes_score",
        "step_description": "Calculate the score based on the presence of diabetes.",
        "step_result": diabetes_score,
        "unit": None
    }

    # Step 8: Calculate the score based on presence of vascular disease or stroke history
    if vascular_disease_or_stroke_history == "No":
        vascular_disease_or_stroke_history_score = 0
    else:
        vascular_disease_or_stroke_history_score = 6
    yield {
        "step_name": "vascular_disease_or_stroke_history_score",
        "step_description": "Calculate the score based on the presence of vascular disease or stroke history.",
        "step_result": vascular_disease_or_stroke_history_score,
        "unit": None
    }

    # Step 9: Calculate the total risk score by summing all individual scores
    total_risk_score = (
        muscle_creatinine_score +
        hematocrit_score +
        heart_rate_score +
        systolic_blood_pressure_score +
        gender_score +
        heart_failure_signs_score +
        diabetes_score +
        vascular_disease_or_stroke_history_score
    )
    yield {
        "step_name": "total_risk_score",
        "step_description": "Calculate the total risk score for major bleeding by summing all individual scores.",
        "step_result": total_risk_score,
        "unit": None
    }

    return total_risk_score
